"use client";
import { useState } from "react";
import AlgorithmSelect from "./simulator/components/AlgorithmSelect";
import ConfigForm from "./simulator/components/ConfigForm";
import GanttChart from "./simulator/components/GanttChart";
import MetricsTable from "./simulator/components/MetricsTable";
import ProcessForm from "./simulator/components/ProcessForm";

export default function SimulatorPage() {
  const [processes, setProcesses] = useState([]);
  const [config, setConfig] = useState({
    quantum: 2,
    sobrecarga_contexto: 1,
    algoritmo: "FCFS",
  });
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  async function handleSimulate() {
    setLoading(true);
    try {
      const response = await fetch("/api/simulate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...config, processos: processes }),
      });
      const data = await response.json();
      setResults(data);
    } catch (error) {
      console.error("Erro ao simular:", error);
    }
    setLoading(false);
  }

  return (
    <main className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-5xl mx-auto space-y-8">
        <div className="bg-white shadow-md rounded-2xl p-6">
          <h1 className="text-2xl font-bold mb-4 text-gray-800">
            Simulador de Escalonamento
          </h1>

          <ConfigForm config={config} setConfig={setConfig} />
          <AlgorithmSelect config={config} setConfig={setConfig} />
          <ProcessForm processes={processes} setProcesses={setProcesses} />

          <div className="flex justify-end mt-4">
            <button
              onClick={handleSimulate}
              disabled={loading}
              className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
            >
              {loading ? "Simulando..." : "Iniciar Simulação"}
            </button>
          </div>
        </div>

        {results && (
          <>
            <div className="bg-white shadow-md rounded-2xl p-6">
              <h2 className="text-xl font-semibold mb-3">Gráfico de Gantt</h2>
              <GanttChart renders={results.renders} />
            </div>

            <div className="bg-white shadow-md rounded-2xl p-6">
              <h2 className="text-xl font-semibold mb-3">Métricas</h2>
              <MetricsTable metrics={results.metrics} summary={results.summary} />
            </div>
          </>
        )}
      </div>
    </main>
  );
}
